if (typeof PALETTE_DATA !== "undefined" && typeof PALETTE_CHAOS_DATA === "undefined") {
  const paletteChaosColors = [];

  if (typeof DATA !== "undefined" && Array.isArray(DATA.palettes)) {
    DATA.palettes.forEach(palette => {
      String(palette).split(",").forEach(color => {
        const clean = color.trim();
        if (clean && !paletteChaosColors.includes(clean)) paletteChaosColors.push(clean);
      });
    });
  }

  if (Array.isArray(PALETTE_DATA.palettes)) {
    PALETTE_DATA.palettes.forEach(palette => {
      if (Array.isArray(palette.colors)) {
        palette.colors.forEach(color => {
          const clean = color.name || color.hex || "";
          if (clean && !paletteChaosColors.includes(clean)) paletteChaosColors.push(clean);
        });
      }
    });
  }

  var PALETTE_CHAOS_DATA = {
    colors: paletteChaosColors
  };
}

